+export function matchBoundaryFileOpenFailure<T>(
+  failure: BoundaryFileOpenFailure,
+  handlers: {
+    path?: (failure: BoundaryFileOpenFailure) => T;
+    validation?: (failure: BoundaryFileOpenFailure) => T;
+    io?: (failure: BoundaryFileOpenFailure) => T;
